13	/**
14	 * Detect whether an .ai file is a sentinel (saved without PDF compatibility).
15	 *
16	 * Uses mupdf text extraction on page 0 — the only reliable method.
17	 * Checking for "/CompatibilityAlert" in raw bytes is NOT reliable: the procedure
18	 * is defined in the resource dictionary of ALL modern .ai PDFs, so a byte-search
19	 * matches every .ai file regardless of whether it has real artwork.
20	 *
21	 * Sentinel files render a single page whose extracted text contains the canonical
22	 * Adobe warning phrase. Real files have actual artwork and no such text on page 0.
23	 */
24	async function detectSentinel(filePath: string): Promise<boolean> {
25	  const buf = Buffer.alloc(512);
26	  let headStr: string;
27	  const fh = await open(filePath, "r");
28	  try {
29	    const { bytesRead } = await fh.read(buf, 0, 512, 0);
30	    headStr = buf.slice(0, bytesRead).toString("latin1");
31	  } finally {
32	    await fh.close();
33	  }
34	
35	  // Old format: pure PostScript, no PDF layer.
36	  if (headStr.startsWith("%!PS-Adobe-") && !headStr.includes("%PDF-")) {
37	    return true;
38	  }
39	
40	  // Modern format: open with mupdf and extract page-0 text.
41	  const fileBuffer = await readFile(filePath);
42	  const doc = mupdf.Document.openDocument(fileBuffer, "application/pdf");
43	  if (doc.countPages() === 0) return false;
44	  const text = doc.loadPage(0).toStructuredText("preserve-whitespace").asText();
45	  return text.includes("saved without PDF Content");
46	}
