48	export async function runAiSentinelScan(
49	  assets: SentinelAsset[],
50	  nasContainerMountRoot: string,
51	): Promise<void> {
52	  logger.info("AI sentinel scan batch starting", { count: assets.length });
53	
54	  const results: api.AiSentinelScanResult[] = [];
55	  let sentinelCount = 0;
56	
57	  for (const asset of assets) {
58	    const absolutePath = join(nasContainerMountRoot, asset.relative_path);
59	    try {
60	      const isSentinel = await detectSentinel(absolutePath);
61	      results.push({ asset_id: asset.id, filename: asset.filename, relative_path: asset.relative_path, is_sentinel: isSentinel });
62	      if (isSentinel) {
63	        sentinelCount++;
64	        logger.debug("Sentinel .ai detected", { path: asset.relative_path });
65	      }
66	    } catch (e) {
67	      logger.warn("AI sentinel check failed", { path: asset.relative_path, error: (e as Error).message });
68	      results.push({ asset_id: asset.id, filename: asset.filename, relative_path: asset.relative_path, is_sentinel: false });
69	    }
70	  }
71	
72	  logger.info("AI sentinel scan batch done", { checked: results.length, sentinel: sentinelCount });
73	  await api.completeAiSentinelScan(results);
74	}
