32	function withTimeout<T>(promise: Promise<T>, ms: number, label: string): Promise<T> {
33	  return Promise.race([
34	    promise,
35	    new Promise<T>((_, reject) =>
36	      setTimeout(() => reject(new Error(`sharp timeout after ${ms}ms (${label})`)), ms)
37	    ),
38	  ]);
39	}
