56	/**
57	 * Generate a thumbnail for a PSD file.
58	 * Sharp can read PSD files directly (flattened composite).
59	 */
60	async function thumbnailPsd(filePath: string): Promise<ThumbnailResult> {
61	  try {
62	    const psdWork = async () => {
63	      // Pre-read into buffer so the OS file handle is released before we enter
64	      // the sharp pipeline.  If the pipeline hangs and withTimeout fires, the fd
65	      // is already closed — no leaked handles from timed-out processing.
66	      const fileBuffer = await readFile(filePath);
67	      const img = sharp(fileBuffer, { pages: -1 }).flatten({ background: "#ffffff" });
68	      const meta = await withTimeout(img.metadata(), SHARP_TIMEOUT_MS, "psd.metadata");
69	      const resized = img.resize(THUMB_MAX_DIM, THUMB_MAX_DIM, { fit: "inside", withoutEnlargement: true });
70	      const buffer = await withTimeout(resized.jpeg({ quality: 85 }).toBuffer(), SHARP_TIMEOUT_MS, "psd.toBuffer");
71	      const outMeta = await withTimeout(sharp(buffer).metadata(), SHARP_TIMEOUT_MS, "psd.outMeta");
72	      return {
73	        buffer,
74	        width: outMeta.width || meta.width || 0,
75	        height: outMeta.height || meta.height || 0,
76	      };
77	    };
78	    return await withTimeout(psdWork(), PSD_TOTAL_TIMEOUT_MS, "psd.total");
79	  } catch (e) {
80	    logger.warn("Sharp PSD failed", { filePath, error: (e as Error).message });
81	  }
82	
83	  // Fallback: Try sibling image in same directory
84	  try {
85	    return await thumbnailFromSibling(filePath);
86	  } catch (e) {
87	    logger.warn("No sibling image found for PSD", { filePath });
88	  }
89	
90	  throw new Error("no_preview_or_render_failed");
91	}
