94	 * Detect AI files saved without PDF compatibility.
95	 *
96	 * When Illustrator saves without the "PDF compatibility" option, the embedded PDF
97	 * contains only Adobe's compatibility-alert warning page instead of real artwork.
98	 *
99	 * Detection strategy:
100	 *  1. Pure-PostScript .ai (old format): header starts with %!PS-Adobe- and has no %PDF- marker.

100	 *  1. Pure-PostScript .ai (old format): header starts with %!PS-Adobe- and has no %PDF- marker.
101	 *  2. PDF-wrapped .ai (modern format): use mupdf to extract page-0 text and check for the
102	 *     canonical sentinel phrase. This is the only reliable method — /CompatibilityAlert is
103	 *     defined in the resource dictionary of ALL modern .ai PDFs (not just sentinels), so a
104	 *     header string-search produces 100% false positives.
105	 *
106	 * Returns true if the file should skip PDF-based rendering.
107	 */
108	export async function isAiWithoutPdfCompat(filePath: string): Promise<boolean> {
109	  const fh = await open(filePath, "r");
110	  let head: string;
111	  try {
112	    const buf = Buffer.alloc(512);
113	    const { bytesRead } = await fh.read(buf, 0, 512, 0);
114	    head = buf.slice(0, bytesRead).toString("latin1");
115	  } finally {
116	    await fh.close();
117	  }
118	
119	  // Old format: pure PostScript — no PDF stream at all.
120	  if (head.startsWith("%!PS-Adobe-") && !head.includes("%PDF-")) {
121	    return true;
122	  }
123	
124	  // Modern format: PDF-wrapped. Use mupdf text extraction — the only reliable signal.
125	  // Sentinel files render a single page whose text contains the warning phrase.
126	  // (Checking for "/CompatibilityAlert" in raw bytes is wrong: it appears in the
127	  // resource dictionary of every modern .ai PDF, including fully-compatible ones.)
128	  try {
129	    const fileBuffer = await readFile(filePath);
130	    const doc = mupdf.Document.openDocument(fileBuffer, "application/pdf");
131	    if (doc.countPages() === 0) return false;
132	    const text = doc.loadPage(0).toStructuredText("preserve-whitespace").asText();
133	    return text.includes("saved without PDF Content");
134	  } catch {
135	    return false;
136	  }
137	}
