147	/**
148	 * Checks whether a stored thumbnail URL visually shows an Illustrator
149	 * compatibility-alert warning page (the "no PDF compatibility" notice)
150	 * rather than real artwork.
151	 *
152	 * Strategy: OCR the thumbnail and look for the word "compatibility", which
153	 * Illustrator's warning page always contains prominently. Real artwork
154	 * thumbnails virtually never include that word.
155	 *
156	 * Returns false conservatively on fetch/OCR errors — better to miss one
157	 * than to accidentally clear a good thumbnail.
158	 *
159	 * Pass a pre-created worker (createCompatAuditWorker) to avoid reloading
160	 * the language model for every image in a batch.
161	 */
162	export async function isCompatAlertThumbnail(
163	  thumbnailUrl: string,
164	  worker: Awaited<ReturnType<typeof createWorker>>,
165	): Promise<boolean> {
166	  try {
167	    const resp = await fetch(thumbnailUrl);
168	    if (!resp.ok) return false;
169	    const imgBuffer = Buffer.from(await resp.arrayBuffer());
170	
171	    const { data: { text } } = await worker.recognize(imgBuffer);
172	    const lower = text.toLowerCase();
173	
174	    // The Illustrator compatibility-alert page always contains "compatibility"
175	    // as a prominent heading. Real-artwork thumbnails never do.
176	    return lower.includes("compatibility");
177	  } catch (e) {
178	    logger.warn("isCompatAlertThumbnail: check failed — skipping", {
179	      url: thumbnailUrl,
180	      error: (e as Error).message,
181	    });
182	    return false;
183	  }
184	}
