68	// ── AI vision call (provider-agnostic, resolved from model catalog) ──────────
69	
70	async function callAiVision(pngBuffer: Buffer, aiConfig: AiConfig): Promise<string> {
71	  const modelId = aiConfig.pdf_extraction?.ai_vision_model_id;
72	  if (!modelId) return "";
73	
74	  const modelDef = aiConfig.models.find((m) => m.id === modelId);
75	  if (!modelDef) {
76	    logger.warn("PDF text sample: ai vision model not found in catalog", { modelId });
77	    return "";
78	  }
79	  if (!modelDef.capabilities.includes("vision")) {
80	    logger.warn("PDF text sample: selected model has no vision capability", { modelId });
81	    return "";
82	  }
83	
84	  const base64 = pngBuffer.toString("base64");
85	
86	  if (modelDef.provider === "google") {
87	    if (!aiConfig.googleApiKey) {
88	      logger.warn("PDF text sample: GOOGLE_AI_API_KEY not configured");
89	      return "";
90	    }
91	    const url = `https://generativelanguage.googleapis.com/v1beta/models/${modelDef.apiModel}:generateContent?key=${aiConfig.googleApiKey}`;
92	    const res = await fetch(url, {
93	      method: "POST",
94	      headers: { "Content-Type": "application/json" },
95	      signal: AbortSignal.timeout(60_000),
96	      body: JSON.stringify({
97	        contents: [{
98	          role: "user",
99	          parts: [
100	            { inlineData: { mimeType: "image/png", data: base64 } },
101	            { text: "Extract all text from this document page. Return only the raw extracted text with no commentary." },
102	          ],
103	        }],
104	      }),
105	    });
106	    if (!res.ok) {
107	      const errText = await res.text();
108	      throw new Error(`Gemini API ${res.status}: ${errText.slice(0, 200)}`);
109	    }
110	    // eslint-disable-next-line @typescript-eslint/no-explicit-any
111	    const data = await res.json() as any;
112	    return (data?.candidates?.[0]?.content?.parts?.[0]?.text as string || "").trim();
113	
114	  } else if (modelDef.provider === "anthropic") {
115	    if (!aiConfig.anthropicApiKey) {
116	      logger.warn("PDF text sample: ANTHROPIC_API_KEY not configured");
117	      return "";
118	    }
119	    const anthropic = new Anthropic({ apiKey: aiConfig.anthropicApiKey });
120	    const aiResponse = await anthropic.messages.create({
121	      model: modelDef.apiModel,
122	      max_tokens: 2048,
123	      messages: [{
124	        role: "user",
125	        content: [
126	          { type: "image", source: { type: "base64", media_type: "image/png", data: base64 } },
127	          { type: "text", text: "Extract all text from this document page. Return only the raw extracted text with no commentary." },
128	        ],
129	      }],
130	    });
131	    const first = aiResponse.content[0];
132	    return (first.type === "text" ? first.text : "").trim();
133	  }
134	
135	  logger.warn("PDF text sample: unsupported ai vision provider", { provider: modelDef.provider });
136	  return "";
137	}
