165	// ── Process a single PDF ─────────────────────────────────────────────────────
166	
167	async function processSinglePdf(
168	  asset: PdfSampleAsset,
169	  fullPath: string,
170	  aiConfig: AiConfig,
171	  index: number,
172	  total: number,
173	  fileResults: FileProgressEntry[],
174	): Promise<PdfTextSampleResult> {
175	  await reportProgress(index, total, asset.filename, "reading", fileResults);
176	
177	  // .ai files: detect sentinels via mupdf text extraction on page 0.
178	  // Header byte-search for "/CompatibilityAlert" is unreliable — that string is defined
179	  // in the resource dictionary of ALL modern .ai PDFs, not just sentinels.
180	  if (asset.filename.toLowerCase().endsWith(".ai")) {
181	    const SENTINEL_PHRASE = "This is an Adobe® Illustrator® File that was saved without PDF Content.";
182	    try {
183	      // Old format: pure PostScript, no PDF layer — always a sentinel.
184	      const fh = await fsOpen(fullPath, "r");
185	      let isPurePs = false;
186	      try {
187	        const hbuf = Buffer.alloc(512);
188	        const { bytesRead } = await fh.read(hbuf, 0, 512, 0);
189	        const h = hbuf.slice(0, bytesRead).toString("latin1");
190	        isPurePs = h.startsWith("%!PS-Adobe-") && !h.includes("%PDF-");
191	      } finally {
192	        await fh.close();
193	      }
194	
195	      if (isPurePs) {
196	        return {
197	          asset_id: asset.id, filename: asset.filename, relative_path: asset.relative_path,
198	          extraction_method: "pdf_text", extracted_text: SENTINEL_PHRASE,
199	          page_count: 1, char_count: SENTINEL_PHRASE.length, extraction_error: null,
200	        };
201	      }
202	
203	      // Modern format: open with mupdf, extract page-0 text.
204	      const aiBuffer = await readFile(fullPath);
205	      const aiDoc = mupdf.Document.openDocument(aiBuffer, "application/pdf");
206	      const numPages = aiDoc.countPages();
207	      const aiText = numPages > 0
208	        ? aiDoc.loadPage(0).toStructuredText("preserve-whitespace").asText().trim()
209	        : "";
210	      const isSentinel = aiText.includes("saved without PDF Content");
211	      return {
212	        asset_id: asset.id, filename: asset.filename, relative_path: asset.relative_path,
213	        extraction_method: "pdf_text",
214	        extracted_text: isSentinel ? SENTINEL_PHRASE : (aiText || null),
215	        page_count: numPages, char_count: isSentinel ? SENTINEL_PHRASE.length : aiText.length,
216	        extraction_error: null,
217	      };
218	    } catch (aiErr) {
219	      logger.warn("PDF text sample: .ai mupdf check failed", { filename: asset.filename, error: (aiErr as Error).message });
220	      return {
221	        asset_id: asset.id, filename: asset.filename, relative_path: asset.relative_path,
222	        extraction_method: "failed", extracted_text: null,
223	        page_count: null, char_count: 0,
224	        extraction_error: ((aiErr as Error).message).slice(0, 500),
225	      };
226	    }
227	  }
228	
229	  // Check file size before loading into memory
230	  const fileStat = await stat(fullPath);
231	  if (fileStat.size > PDF_SIZE_LIMIT_BYTES) {
232	    const skipReason = `File too large (${(fileStat.size / 1024 / 1024).toFixed(1)} MB > ${PDF_SIZE_LIMIT_BYTES / 1024 / 1024} MB limit)`;
233	    logger.warn("PDF text sample: skipping oversized file", {
234	      filename: asset.filename, size_bytes: fileStat.size, limit_bytes: PDF_SIZE_LIMIT_BYTES,
235	    });
236	    return {
237	      asset_id: asset.id, filename: asset.filename, relative_path: asset.relative_path,
238	      extraction_method: "skipped", extracted_text: null,
239	      page_count: null, char_count: 0,
240	      extraction_error: null, skip_reason: skipReason,
241	    };
242	  }
243	
244	  const buffer = await readFile(fullPath);
245	
246	  let rawText = "";
247	  let numPages: number | null = null;
248	  let mupdfDoc: ReturnType<typeof mupdf.Document.openDocument> | null = null;
249	
250	  // ── Step 1: mupdf text extraction ───────────────────────────────────
251	  await reportProgress(index, total, asset.filename, "mupdf", fileResults);
252	  try {
253	    mupdfDoc = mupdf.Document.openDocument(buffer, "application/pdf");
254	    numPages = mupdfDoc.countPages();
255	    const parts: string[] = [];
256	    for (let p = 0; p < numPages; p++) {
257	      parts.push(mupdfDoc.loadPage(p).toStructuredText("preserve-whitespace").asText());
258	    }
259	    rawText = parts.join("\n");
260	  } catch (mupdfErr) {
261	    logger.warn("PDF text sample: mupdf text extraction failed", {
262	      filename: asset.filename, error: (mupdfErr as Error).message,
263	    });
264	  }
265	
266	  const text = rawText.trim();
267	  const charCount = text.length;
268	
269	  if (charCount >= 100) {
270	    logger.info("PDF text sample: extracted via mupdf text", {
271	      filename: asset.filename, chars: charCount, pages: numPages,
272	    });
273	    return {
274	      asset_id: asset.id, filename: asset.filename, relative_path: asset.relative_path,
275	      extraction_method: "pdf_text", extracted_text: text,
276	      page_count: numPages, char_count: charCount, extraction_error: null,
277	    };
278	  }
279	
280	  // ── Step 2: render page 0 to PNG ────────────────────────────────────
281	  await reportProgress(index, total, asset.filename, "rendering", fileResults);
282	  let pngBuffer: Buffer | null = null;
283	  let thumbnailUrl: string | undefined;
284	  try {
285	    if (!mupdfDoc) {
286	      mupdfDoc = mupdf.Document.openDocument(buffer, "application/pdf");
287	      numPages = mupdfDoc.countPages();
288	    }
289	    const page = mupdfDoc.loadPage(0);
290	    // eslint-disable-next-line @typescript-eslint/no-explicit-any
291	    const pixmap = page.toPixmap([2, 0, 0, 2, 0, 0] as any, (mupdf as any).ColorSpace.DeviceRGB, false);
292	    pngBuffer = Buffer.from(pixmap.asPNG() as Uint8Array);
293	    // Upload thumbnail so the UI can show a preview (best-effort, non-fatal)
294	    try {
295	      thumbnailUrl = await uploadPdfPage(asset.id, 0, pngBuffer);
296	    } catch (uploadErr) {
297	      logger.warn("PDF text sample: thumbnail upload failed (non-fatal)", {
298	        filename: asset.filename, error: (uploadErr as Error).message,
299	      });

1	/**
2	 * Handlers for the .ai sentinel cleanup flow.
3	 *
4	 * "Sentinel" .ai files are those saved from Illustrator without the
5	 * "Create PDF Compatible File" option — their embedded PDF contains only
6	 * Adobe's boilerplate warning text, not the actual artwork.
7	 *
8	 * TEMPORARY — delete these handlers (and the ai_sentinel_cleanup_log table,
9	 * ai_sentinel_stats_fn migration, and the Settings UI card) once the
10	 * reconciliation pass is complete and ingestion logic prevents this from
11	 * recurring. See CLAUDE.md for details.
12	 */
13	
14	import { err, json } from "../http.ts";
15	import { serviceClient } from "../service-client.ts";
16	import { credentialsFromConfig, deleteSpacesObjects } from "../spaces-delete.ts";
17	import { requireBridgeLatest } from "../bridge-version.ts";
18	import { markAiIgnored } from "../mark-ai-ignored.ts";
19	import { handleListSiblingImages } from "./sibling-scan-handlers.ts";
20	
21	const SENTINEL_TEXT = "saved without PDF Content";
22	
23	// ── GET: stats + pending files (with asset thumbnails) + recent log ──────────
24	
25	export async function handleGetAiSentinelStatus() {
26	  const db = serviceClient();
27	  try {
28	    const [statsRes, logRes, pendingRes, cleanedUpRes, scanReqRes] = await Promise.all([
29	      db.rpc("get_ai_sentinel_stats"),
30	      db
31	        .from("ai_sentinel_cleanup_log")
32	        .select("id, ai_filename, ai_relative_path, replacement_filename, replacement_queued_for_thumbnail, created_at")
33	        .order("created_at", { ascending: false })
34	        .limit(100),
35	      // Fetch sentinel files with their asset thumbnails so the UI can show them for visual verification.
36	      // PostgREST can't parse a SQL subquery as a list of UUID values, so we filter
37	      // already-cleaned-up assets in application code (cleanedUpRes below).
38	      db
39	        .from("pdf_text_samples")
40	        .select("asset_id, filename, relative_path, assets!inner(thumbnail_url, is_deleted)")
41	        .like("extracted_text", `%${SENTINEL_TEXT}%`)
42	        .eq("assets.is_deleted", false)
43	        .limit(200),
44	      db.from("ai_sentinel_cleanup_log").select("ai_asset_id"),
45	      db.from("admin_config").select("value").eq("key", "AI_SENTINEL_SCAN_REQUEST").maybeSingle(),
46	    ]);
47	
48	    if (statsRes.error) throw new Error(`Stats RPC failed: ${statsRes.error.message}`);
49	
50	    const alreadyCleaned = new Set(
51	      ((cleanedUpRes.data ?? []) as Array<{ ai_asset_id: string }>).map((r) => r.ai_asset_id),
52	    );
53	
54	    // Flatten the join: pull thumbnail_url out of the nested assets object
55	    const rawPending = ((pendingRes.data ?? []) as unknown as Array<{
56	      asset_id: string;
57	      filename: string;
58	      relative_path: string;
59	      assets: { thumbnail_url: string | null; is_deleted?: boolean | null } | Array<{ thumbnail_url: string | null; is_deleted?: boolean | null }> | null;
60	    }>).filter((r) => !alreadyCleaned.has(r.asset_id));
61	
62	    // For each pending sentinel, find the best sibling tech-pack thumbnail
63	    // (the .ai itself has no thumbnail — we show the replacement so the user
64	    // can visually verify the detection is correct before deleting).
65	    const dirPrefixes = [...new Set(rawPending.map((r) => r.relative_path.replace(/\/[^/]*$/, "")))];
66	    const replacementMap: Map<string, { thumbnail_url: string; filename: string }> = new Map();
67	
68	    if (dirPrefixes.length > 0) {
69	      // Query each directory individually — .or() with multi-word paths breaks
70	      // the PostgREST parser because spaces in values are not quoted.
71	      await Promise.all(dirPrefixes.map(async (dir) => {
72	        const { data: siblings } = await db
73	          .from("assets")
74	          .select("filename, thumbnail_url")
75	          .in("file_type", ["pdf", "png", "jpg"])
76	          .eq("is_deleted", false)
77	          .not("thumbnail_url", "is", null)
78	          .like("relative_path", `${dir}/%`)
79	          .limit(20);
80	        const rows = (siblings ?? []) as Array<{ filename: string; thumbnail_url: string }>;
81	        const techPack = rows.find((r) => /tech.?pack/i.test(r.filename));
82	        const best = techPack ?? rows[0] ?? null;
83	        if (best) replacementMap.set(dir, { thumbnail_url: best.thumbnail_url, filename: best.filename });
84	      }));
85	    }
86	
87	    const pendingFiles = rawPending.map((r) => {
88	      const dir = r.relative_path.replace(/\/[^/]*$/, "");
89	      const asset = Array.isArray(r.assets) ? r.assets[0] : r.assets;
90	      const replacement = replacementMap.get(dir) ?? null;
91	      return {
92	        asset_id: r.asset_id,
93	        filename: r.filename,
94	        relative_path: r.relative_path,
95	        thumbnail_url: asset?.thumbnail_url ?? null,
96	        replacement_thumbnail_url: replacement?.thumbnail_url ?? null,
97	        replacement_filename: replacement?.filename ?? null,
98	      };
99	    });
100	
101	    const scanRequest = (scanReqRes.data?.value as Record<string, unknown>) ?? null;
102	
103	    return json({
104	      ok: true,
105	      stats: statsRes.data,
106	      pending_files: pendingFiles,
107	      recent_log: logRes.data ?? [],
108	      scan_request: scanRequest,
109	    });
110	  } catch (e) {
111	    return err((e as Error).message, 500);
112	  }
113	}
