115	// ── POST: run a cleanup batch ─────────────────────────────────────────
116	
117	export async function handleRunAiSentinelCleanup(body: Record<string, unknown>) {
118	  const db = serviceClient();
119	  const limit = Math.min(Number(body.limit) || 50, 200);
120	  // If the caller passes specific asset_ids, only process those; otherwise batch up to limit.
121	  const requestedIds = Array.isArray(body.asset_ids) && (body.asset_ids as unknown[]).length > 0 ? (body.asset_ids as string[]) : null;
122	
123	  // 1. Find .ai assets with sentinel text and no thumbnail, not yet cleaned up
124	  let pendingQuery = db
125	    .from("pdf_text_samples")
126	    .select("asset_id, filename, relative_path, extraction_method")
127	    .like("extracted_text", `%${SENTINEL_TEXT}%`);
128	
129	  if (requestedIds) {
130	    pendingQuery = pendingQuery.in("asset_id", requestedIds);
131	  } else {
132	    pendingQuery = pendingQuery.limit(limit * 2);
133	  }
134	
135	  const { data: pending, error: pendingErr } = await pendingQuery;
136	
137	  if (pendingErr) return err(`Query failed: ${pendingErr.message}`, 500);
138	  if (!pending || pending.length === 0) {
139	    return json({ ok: true, processed: 0, message: "No sentinel .ai files pending cleanup" });
140	  }
141	
142	  // Filter to assets that are still alive, have no thumbnail, and not yet in the log
143	  const assetIds = pending.map((r: { asset_id: string }) => r.asset_id);
144	  const [assetsRes, alreadyDoneRes] = await Promise.all([
145	    db.from("assets").select("id, filename, relative_path, thumbnail_url, style_group_id")
146	      .in("id", assetIds)
147	      .eq("is_deleted", false)
148	      .eq("file_type", "ai"),
149	    db.from("ai_sentinel_cleanup_log").select("ai_asset_id").in("ai_asset_id", assetIds),
150	  ]);
151	
152	  const alreadyDone = new Set((alreadyDoneRes.data ?? []).map((r: { ai_asset_id: string }) => r.ai_asset_id));
153	  const assets = (assetsRes.data ?? []).filter((a: { id: string }) => !alreadyDone.has(a.id)).slice(0, limit);
154	
155	  if (assets.length === 0) {
156	    return json({ ok: true, processed: 0, message: "All found sentinel files already cleaned up" });
157	  }
158	
159	  // Load DO Spaces credentials once
160	  const { data: configRows } = await db
161	    .from("admin_config")
162	    .select("key, value")
163	    .in("key", ["DO_SPACES_KEY", "DO_SPACES_SECRET", "SPACES_CONFIG"]);
164	
165	  const configMap: Record<string, unknown> = {};
166	  for (const row of configRows ?? []) configMap[row.key] = row.value;
167	  const creds = credentialsFromConfig(configMap);
168	
169	  const results: Array<{
170	    ai_asset_id: string;
171	    ai_filename: string;
172	    replacement_asset_id: string | null;
173	    replacement_filename: string | null;
174	    queued: boolean;
175	  }> = [];
176	
177	  for (const asset of assets as Array<{ id: string; filename: string; relative_path: string; thumbnail_url: string | null; style_group_id: string | null }>) {
178	    // 2. Soft-delete the .ai asset
179	    await db.from("assets").update({ is_deleted: true, thumbnail_url: null }).eq("id", asset.id);
180	
181	    // 3. Add to scanner permanent ignore list — bridge will never re-ingest this path
182	    await markAiIgnored(db, asset.relative_path, "no_pdf_compat");
183	
184	    // 4. Delete its thumbnail from DO Spaces
185	    if (asset.thumbnail_url && creds) {
186	      try {
187	        await deleteSpacesObjects([`thumbnails/${asset.id}.jpg`], creds);
188	      } catch (e) {
189	        console.warn(`ai-sentinel: thumbnail delete failed for ${asset.id}:`, (e as Error).message);
190	      }
191	    }
192	
193	    // 5. Queue a sibling image scan for this folder using the standard list-sibling-images
194	    // flow. The bridge will find any JPG/PNG/PDF on disk; the user can then choose to
195	    // ingest them via the normal sibling scan UI. We do not auto-ingest here.
196	    const folderPath = asset.relative_path.replace(/\/[^/]*$/, "");
197	    await handleListSiblingImages({ folder_path: folderPath, style_group_id: asset.style_group_id ?? undefined });
198	
199	    // 6. Log the action (no replacement recorded — user picks from sibling scan results)
200	    await db.from("ai_sentinel_cleanup_log").insert({
201	      ai_asset_id: asset.id,
202	      ai_filename: asset.filename,
203	      ai_relative_path: asset.relative_path,
204	      replacement_asset_id: null,
205	      replacement_filename: null,
206	      replacement_relative_path: null,
207	      replacement_had_thumbnail: null,
208	      replacement_queued_for_thumbnail: false,
209	    });
210	
211	    results.push({
212	      ai_asset_id: asset.id,
213	      ai_filename: asset.filename,
214	      replacement_asset_id: null,
215	      replacement_filename: null,
216	      queued: false,
217	    });
218	  }
219	
220	  return json({
221	    ok: true,
222	    processed: results.length,
223	    sibling_scans_queued: results.length,
224	    results,
225	  });
226	}
