228	// ── POST: start an AI sentinel scan ──────────────────────────────────────────
229	
230	const AI_SENTINEL_BATCH_SIZE = 50;
231	
232	export async function handleTriggerAiSentinelScan(body: Record<string, unknown>) {
233	  const db = serviceClient();
234	
235	  const versionErr = await requireBridgeLatest(db);
236	  if (versionErr) return versionErr;
237	
238	  // Block if an active PDF sample (non-sentinel) is already running
239	  const { data: existing } = await db.from("admin_config").select("value").eq("key", "PDF_TEXT_SAMPLE_REQUEST").maybeSingle();
240	  const existingReq = existing?.value as Record<string, unknown> | null;
241	  if (existingReq && (existingReq.status === "pending" || existingReq.status === "processing")) {
242	    return err("A PDF text sample is already in progress. Wait for it to finish first.", 409);
243	  }
244	
245	  const { count: totalAi } = await db
246	    .from("assets")
247	    .select("*", { count: "exact", head: true })
248	    .eq("file_type", "ai")
249	    .eq("is_deleted", false);
250	
251	  const target = Number(body.target) || (totalAi ?? 999_999);
252	
253	  const { data: firstBatch, error } = await db
254	    .from("assets")
255	    .select("id, filename, relative_path")
256	    .eq("file_type", "ai")
257	    .eq("is_deleted", false)
258	    .order("id", { ascending: true })
259	    .limit(AI_SENTINEL_BATCH_SIZE);
260	
261	  if (error) return err(`Failed to fetch .ai assets: ${error.message}`, 500);
262	  if (!firstBatch || firstBatch.length === 0) return err("No .ai assets found", 404);
263	
264	  const lastId = firstBatch[firstBatch.length - 1].id as string;
265	  const nowIso = new Date().toISOString();
266	
267	  // Use the dedicated fast-path: heartbeat reads batch + dispatches trigger_ai_sentinel_scan
268	  // to the bridge which runs a 64KB header check (runAiSentinelScan) per asset.
269	  // complete-ai-sentinel-scan advances the batch until target is met or all assets processed.
270	  await db.from("admin_config").upsert({
271	    key: "AI_SENTINEL_SCAN_REQUEST",
272	    value: {
273	      status: "scanning",
274	      target,
275	      batch_size: AI_SENTINEL_BATCH_SIZE,
276	      found: 0,
277	      processed: 0,
278	      total_ai: totalAi ?? 0,
279	      batch: firstBatch,
280	      last_id: lastId,
281	      started_at: nowIso,
282	    },
283	    updated_at: nowIso,
284	  });
285	
286	  return json({ ok: true, total_ai: totalAi, batch_size: AI_SENTINEL_BATCH_SIZE, target });
287	}
