289	// ── POST: trigger blank thumbnail cleanup ─────────────────────────────────────
290	
291	const BLANK_THUMB_BATCH_SIZE = 25;
292	
293	export async function handleTriggerBlankThumbCleanup() {
294	  const db = serviceClient();
295	
