245	/**
246	 * Detect AI files saved without PDF compatibility.
247	 *
248	 * When saved without the "PDF compatibility" option, the embedded PDF contains only
249	 * a /CompatibilityAlert form XObject. Ghostscript, Sharp, and Poppler all "succeed"
250	 * but render the warning notice rather than actual artwork.
251	 *
252	 * Returns true if PDF-based rendering should be skipped.
253	 * Inkscape (which reads the native AI/SVG format) is still worth trying.
254	 */
255	async function isAiWithoutPdfCompat(filePath: string): Promise<boolean> {
256	  const READ_SIZE = 65536; // 64 KB — enough for DSC comments and PDF structure markers
257	  const fh = await open(withLongPathPrefix(filePath), "r");
258	  try {
259	    const buf = Buffer.alloc(READ_SIZE);
260	    const { bytesRead } = await fh.read(buf, 0, READ_SIZE, 0);
261	    const head = buf.slice(0, bytesRead).toString("latin1");
262	
263	    // Older format: pure PostScript without embedded PDF stream
264	    if (head.startsWith("%!PS-Adobe-") && !head.includes("%PDF-")) {
265	      return true;
266	    }
267	
268	    // Modern format: PDF-wrapped but page content calls /CompatibilityAlert form
269	    if (head.includes("/CompatibilityAlert")) {
270	      return true;
271	    }
272	
273	    return false;
274	  } finally {
275	    await fh.close();
276	  }
277	}
